(async () => {
  const CFG = {
    reach:         1.5,
    includeSecret: false,
  };

  function pointToSegDist(px, py, ax, ay, bx, by) {
    const dx = bx - ax, dy = by - ay;
    const lenSq = dx * dx + dy * dy;
    if (lenSq === 0) return Math.hypot(px - ax, py - ay);
    const t = Math.max(0, Math.min(1, ((px - ax) * dx + (py - ay) * dy) / lenSq));
    return Math.hypot(px - (ax + t * dx), py - (ay + t * dy));
  }

  const token = canvas.tokens.controlled[0];
  if (!token) return ui.notifications.warn("Open Door: select your token first.");

  const cx = token.x + token.w / 2;
  const cy = token.y + token.h / 2;
  const maxDist = CFG.reach * canvas.grid.size;

  const DOOR  = CONST.WALL_DOOR_TYPES;
  const STATE = CONST.WALL_DOOR_STATES;

  const nearby = canvas.walls.placeables
    .filter(w => {
      if (w.document.door === DOOR.NONE)   return false;
      if (w.document.door === DOOR.SECRET && !CFG.includeSecret) return false;
      const [x1, y1, x2, y2] = w.document.c;
      return pointToSegDist(cx, cy, x1, y1, x2, y2) <= maxDist;
    })
    .sort((a, b) => {
      const [ax1, ay1, ax2, ay2] = a.document.c;
      const [bx1, by1, bx2, by2] = b.document.c;
      return pointToSegDist(cx, cy, ax1, ay1, ax2, ay2)
           - pointToSegDist(cx, cy, bx1, by1, bx2, by2);
    });

  if (!nearby.length) return ui.notifications.warn("No door within reach.");

  const door = nearby[0];
  const ds   = door.document.ds;

  if (ds === STATE.LOCKED) {
    return ui.notifications.warn("That door is locked.");
  }

  const newState = ds === STATE.OPEN ? STATE.CLOSED : STATE.OPEN;
  await door.document.update({ ds: newState });

  ui.notifications.info(newState === STATE.OPEN ? "Door opened." : "Door closed.");
})();
